function isValidParentheses(s) {
  const pairs = { ")": "(", "]": "[", "}": "{" };
  const stack = [];

  for (const ch of s) {
    if (ch === "(" || ch === "[" || ch === "{") {
      stack.push(ch);
    } else if (pairs[ch]) {
      if (stack.length === 0 || stack.pop() !== pairs[ch]) return false;
    }
  }

  return stack.length === 0;
}

