function topoSort(graph) {
  const visited = new Set();
  const result = [];
  function dfs(node) {
    if (visited.has(node)) return;
    visited.add(node);
    for (const neighbor of graph[node]) dfs(neighbor);
    result.unshift(node);
  }
  for (const node in graph) dfs(node);
  return result;
}
console.log(topoSort({ a: ["b", "c"], b: ["d"], c: ["d"], d: [] }).join(","));

