class Trie {
  constructor() {
    this.root = {};
  }
  insert(word) {
    let node = this.root;
    for (const ch of word) {
      if (!node[ch]) node[ch] = {};
      node = node[ch];
    }
    node.isEnd = true;
  }
  search(word) {
    let node = this.root;
    for (const ch of word) {
      if (!node[ch]) return false;
      node = node[ch];
    }
    return node.isEnd === true;
  }
}
const t = new Trie();
t.insert("cat");
t.insert("car");
t.insert("card");
console.log(t.search("car"));
console.log(t.search("cab"));

