function createRateLimiter(maxCalls, windowMs) {
  const calls = [];
  return function() {
    const now = Date.now();
    while (calls.length > 0 && calls[0] <= now - windowMs) calls.shift();
    if (calls.length < maxCalls) {
      calls.push(now);
      return true;
    }
    return false;
  };
}
const limiter = createRateLimiter(2, 1000);
console.log(limiter());
